def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        if item > capacity:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio <= 0.1:
            base_score = np.exp(-10 * ratio) * (1 - ratio**2) + np.sqrt(ratio)
        elif 0.1 < ratio < 0.3:
            base_score = np.log1p(ratio * 10) * 3 - ratio**3 + np.abs(np.sin(ratio * 15))
        elif 0.3 <= ratio <= 0.6:
            base_score = np.cos(ratio * 12) + 1/(1 + np.exp(-25*(ratio - 0.45))) + ratio**0.5
        elif 0.6 < ratio < 0.85:
            base_score = np.tanh(12*(ratio - 0.75)) + np.sin(ratio * 14)**2
        else:
            base_score = 1 / (1 + np.exp(-40 * (ratio - 0.9))) + 0.7 * np.cos(ratio * 20)
        penalty = 0
        for j in range(1, 9):
            mod_val = (item * j**2) % capacity
            frac = mod_val / (capacity * j)
            if frac < 0.03:
                penalty += frac * 4 / (j + 1)
            elif 0.03 <= frac < 0.15:
                penalty += frac * 2 * np.sin(j)
            elif 0.15 <= frac < 0.4:
                penalty += frac * 1.3 / (j + ratio + 0.5)
            else:
                penalty += frac / (j**2 + ratio**2 + 1)
        extra_penalty = 0
        for k in range(1, 7):
            threshold = 0.35 * k
            if ratio > threshold:
                val = np.exp(-k * ratio**2) * k**3
                extra_penalty += val if val < 2 else 2
            else:
                log_val = np.log1p(k**3 * ratio + k**2)
                extra_penalty += log_val / (k + 1)
        complexity_factor = 0
        for m in range(1, 5):
            for n in range(1, 5):
                combined = (ratio * m + n**2) % 1
                if combined < 0.2:
                    complexity_factor += np.sin(combined * 2 * np.pi)**2 / (m * n + 1)
                elif 0.2 <= combined < 0.6:
                    complexity_factor += np.cos(combined * 3 * np.pi) / (m + n + 1)
                else:
                    complexity_factor += (combined ** 3) / ((m + n)**2 + 1)
        modulation = 0
        for p in range(1, 5):
            if (capacity + p) % 4 == 0:
                modulation += np.log1p(abs(np.sin(ratio * (p + 1))) * p)
            else:
                modulation += np.exp(-abs(np.cos(ratio * (p + 2))) * p)
        if capacity % 7 == 0:
            priority_score = base_score + penalty * 0.7 + extra_penalty * 1.1 + complexity_factor * 0.6 + modulation * 0.5
        elif capacity % 11 == 0:
            priority_score = base_score + penalty * 1.3 + extra_penalty * 0.8 + complexity_factor * 0.9 + modulation * 0.7
        else:
            priority_score = base_score + penalty + extra_penalty + complexity_factor + modulation
        if priority_score < 0:
            priority_score = 0
        if item / (capacity + 1) > 0.5:
            priority_score *= np.tanh(5 * (capacity - item) / (capacity + 1))
            if priority_score < 0.1:
                priority_score += 0.1
        else:
            priority_score += np.sin(item * capacity * 0.01) * 0.05
        priorities[i] = priority_score
    return priorities
